"use client";

import * as React from "react";
import { AnimatePresence, motion } from "framer-motion";
import { CreditCardPreview } from "@/components/ui/credit-card-preview";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { CreditCardValues, CardType } from "@/types/payment";
import { detectCardType, formatCardNumber } from "@/hooks/use-card-type";
import { cn } from "@/lib/utils";

interface CreditCardFormProps {
  value: CreditCardValues;
  onChange: (value: CreditCardValues) => void;
  cardType?: CardType;
  className?: string;
}

const CARD_LOGOS: Record<string, string> = {
  visa: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/visa.svg",
  mastercard: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/mastercard.svg",
  amex: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/amex.svg",
  paypal: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/paypal.svg",
};

export function CreditCardForm({ value, onChange, cardType: manualType, className }: CreditCardFormProps) {
  const [isCvvFocused, setIsCvvFocused] = React.useState(false);
  const detectedType = detectCardType(value.cardNumber);
  const cardType = manualType && manualType !== "unknown" ? manualType : detectedType;
  const maxCvvLength = cardType === "amex" ? 4 : 3;

  const handleCardNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, "");
    const type = detectCardType(raw);
    const formatted = formatCardNumber(raw, type);
    onChange({ ...value, cardNumber: formatted });
  };

  const handleExpiryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const raw = e.target.value.replace(/\D/g, "").slice(0, 4);
    onChange({
      ...value,
      expiryMonth: raw.slice(0, 2),
      expiryYear: raw.slice(2, 4),
    });
  };

  const expiryDisplay = value.expiryMonth
    ? `${value.expiryMonth}${value.expiryYear ? "/" + value.expiryYear : "/"}`
    : "";

  const expiryError = value.expiryMonth && parseInt(value.expiryMonth) > 12 ? "Mois invalide" : null;

  return (
    <div className={cn("space-y-6 px-6 pb-6", className)}>
      <div className="flex justify-center">
        <CreditCardPreview 
          value={value} 
          cardType={cardType}
          isFlipped={isCvvFocused} 
          className="w-full max-w-[360px]" 
        />
      </div>

      <div className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="cardholderName">Nom sur la carte</Label>
          <Input
            id="cardholderName"
            placeholder="JEAN DUPONT"
            value={value.cardholderName}
            onChange={(e) => onChange({ ...value, cardholderName: e.target.value.toUpperCase() })}
            autoComplete="cc-name"
            className="uppercase placeholder:normal-case"
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="cardNumber">Numéro de carte</Label>
          <div className="relative">
            <Input
              id="cardNumber"
              placeholder="0000 0000 0000 0000"
              value={value.cardNumber}
              onChange={handleCardNumberChange}
              inputMode="numeric"
              autoComplete="cc-number"
              maxLength={cardType === "amex" ? 17 : 19}
              className="font-mono pr-12 tracking-wider"
            />
            <AnimatePresence>
              {CARD_LOGOS[cardType] && (
                <motion.div
                  key={cardType}
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.8 }}
                  className="absolute right-3 top-1/2 -translate-y-1/2 h-5 w-8 flex items-center"
                >
                  <img src={CARD_LOGOS[cardType]} alt={cardType} className="h-full w-auto object-contain" />
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label htmlFor="expiry">Date d'expiration</Label>
            <Input
              id="expiry"
              placeholder="MM/YY"
              value={expiryDisplay}
              onChange={handleExpiryChange}
              inputMode="numeric"
              autoComplete="cc-exp"
              maxLength={5}
              className={cn("font-mono", expiryError && "border-destructive")}
            />
            {expiryError && <p className="text-xs text-destructive">{expiryError}</p>}
          </div>

          <div className="space-y-2">
            <Label htmlFor="cvv">CVV</Label>
            <Input
              id="cvv"
              placeholder={maxCvvLength === 4 ? "••••" : "•••"}
              value={value.cvv}
              onChange={(e) => onChange({ ...value, cvv: e.target.value.replace(/\D/g, "").slice(0, maxCvvLength) })}
              inputMode="numeric"
              autoComplete="cc-csc"
              maxLength={maxCvvLength}
              type="password"
              onFocus={() => setIsCvvFocused(true)}
              onBlur={() => setIsCvvFocused(false)}
              className="font-mono"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { CreditCardValues, CardType } from "@/types/payment";
import { detectCardType, maskCardNumber } from "@/hooks/use-card-type";
import { cn } from "@/lib/utils";

const CARD_LOGOS: Record<string, string> = {
  visa: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/visa.svg",
  mastercard: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/mastercard.svg",
  amex: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/amex.svg",
  paypal: "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/payment-methods/paypal.svg",
};

const CARD_GRADIENTS: Record<string, string> = {
  visa: "from-[#1a1f71] via-[#1a1f71] to-[#f7a600]",
  mastercard: "from-[#eb001b] via-[#ff5f00] to-[#f79e1b]",
  amex: "from-[#007bc1] via-[#005fa0] to-[#003e7e]",
  discover: "from-[#ff6600] via-[#ff8c00] to-[#ffa500]",
  paypal: "from-[#003087] via-[#0070ba] to-[#0070ba]",
  unknown: "from-zinc-800 via-zinc-700 to-zinc-600",
};

interface CreditCardPreviewProps {
  value: CreditCardValues;
  cardType?: CardType;
  isFlipped?: boolean;
  className?: string;
}

export function CreditCardPreview({
  value,
  cardType: manualType,
  isFlipped = false,
  className,
}: CreditCardPreviewProps) {
  const detectedType = detectCardType(value.cardNumber);
  const cardType = manualType && manualType !== "unknown" ? manualType : detectedType;
  const gradient = CARD_GRADIENTS[cardType];
  const maskedNumber = maskCardNumber(value.cardNumber, cardType);
  const displayMonth = value.expiryMonth || "MM";
  const displayYear = value.expiryYear ? value.expiryYear.slice(-2) : "YY";

  return (
    <div
      className={cn("w-full max-w-sm", className)}
      style={{ perspective: "1000px" }}
    >
      <motion.div
        className="relative w-full"
        style={{ transformStyle: "preserve-3d" }}
        animate={{ rotateY: isFlipped ? 180 : 0 }}
        transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
      >
        {/* ── FACE AVANT ── */}
        <div
          className={cn(
            "relative aspect-[1.586/1] w-full rounded-2xl bg-linear-to-br p-6 shadow-2xl overflow-hidden",
            gradient
          )}
          style={{ backfaceVisibility: "hidden" }}
        >
          <div className="absolute inset-0 bg-linear-to-br from-white/20 to-transparent pointer-events-none rounded-2xl" />
          <div className="absolute -top-16 -right-16 size-48 rounded-full bg-white/10 blur-3xl" />
          <div className="absolute -bottom-10 -left-10 size-32 rounded-full bg-black/20 blur-2xl" />

          {/* Puce EMV + Logo réseau */}
          <div className="flex items-start justify-between">
            <svg width="44" height="34" viewBox="0 0 44 34" fill="none">
              <rect width="44" height="34" rx="5" fill="#D4A017"/>
              <rect x="1" y="1" width="42" height="32" rx="4" fill="#E8B923"/>
              <rect x="14" y="1" width="2" height="32" fill="#C8960F" opacity="0.6"/>
              <rect x="28" y="1" width="2" height="32" fill="#C8960F" opacity="0.6"/>
              <rect x="1" y="11" width="42" height="2" fill="#C8960F" opacity="0.6"/>
              <rect x="1" y="21" width="42" height="2" fill="#C8960F" opacity="0.6"/>
              <rect x="14" y="11" width="16" height="12" rx="2" fill="#C8960F" opacity="0.5"/>
            </svg>
            <div className="h-8 w-16 flex items-center justify-end">
              {CARD_LOGOS[cardType] ? (
                <img src={CARD_LOGOS[cardType]} alt={cardType} className="h-full w-auto object-contain drop-shadow-sm" />
              ) : (
                <span className="text-white/60 text-xs font-medium uppercase tracking-widest">CARD</span>
              )}
            </div>
          </div>

          {/* Numéro masqué */}
          <div className="mt-6">
            <p className="font-mono text-xl tracking-[0.2em] text-white drop-shadow whitespace-nowrap" style={{ fontVariantNumeric: "tabular-nums" }}>
              {maskedNumber}
            </p>
          </div>

          {/* Nom + expiry */}
          <div className="mt-4 flex items-end justify-between">
            <div>
              <p className="text-[10px] uppercase tracking-widest text-white/60 mb-1">Card Holder</p>
              <p className="text-sm font-medium uppercase tracking-wider text-white truncate max-w-[160px]">
                {value.cardholderName || "FULL NAME"}
              </p>
            </div>
            <div className="text-right">
              <p className="text-[10px] uppercase tracking-widest text-white/60 mb-1">Expires</p>
              <p className="text-sm font-medium text-white">{displayMonth}/{displayYear}</p>
            </div>
          </div>
        </div>

        {/* ── FACE ARRIÈRE ── */}
        <div
          className={cn(
            "absolute inset-0 aspect-[1.586/1] w-full rounded-2xl bg-linear-to-br overflow-hidden shadow-2xl",
            gradient
          )}
          style={{ backfaceVisibility: "hidden", transform: "rotateY(180deg)" }}
        >
          <div className="absolute inset-0 bg-linear-to-br from-white/10 to-transparent pointer-events-none rounded-2xl" />
          <div className="mt-8 h-12 w-full bg-black/90" />
          <div className="mx-6 mt-4 flex items-center gap-3">
            <div className="flex-1 h-10 bg-white/90 rounded flex items-center px-3">
              <div className="flex gap-[2px] flex-1">
                {Array.from({ length: 20 }).map((_, i) => (
                  <div
                    key={i}
                    className="h-4 w-[3px] rounded-sm"
                    style={{
                      backgroundColor: i % 3 === 0 ? "#e5e7eb" : i % 3 === 1 ? "#d1d5db" : "#f9fafb",
                      transform: `rotate(${(i % 5) * 2 - 4}deg)`,
                    }}
                  />
                ))}
              </div>
              <p className="ml-3 font-mono text-sm font-bold text-black tracking-widest">
                {value.cvv || "•••"}
              </p>
            </div>
          </div>
          {CARD_LOGOS[cardType] && (
            <div className="absolute bottom-4 right-6 h-8 w-16 flex items-center justify-end">
              <img src={CARD_LOGOS[cardType]} alt={cardType} className="h-full w-auto object-contain opacity-80" />
            </div>
          )}
        </div>
      </motion.div>
    </div>
  );
}
